mapper.select:
SELECT i.category_id AS categoryId, COUNT(*) AS count FROM items i WHERE i.deleted = 0 AND i.category_id IN
#{categoryIdItem}
GROUP BY i.category_id

SELECT COUNT(*)
FROM items i

    i.deleted = 0

        AND (
            i.name LIKE CONCAT('%', #{search}, '%')
            OR i.name_zh LIKE CONCAT('%', #{search}, '%')
            OR i.internal_name LIKE CONCAT('%', #{search}, '%')
        )


        AND (
            i.category_id IN

                #{categoryIdItem}

            OR EXISTS (
                SELECT 1
                FROM item_category_rel icr_filter
                WHERE icr_filter.item_id = i.id
                  AND icr_filter.deleted = 0
                  AND icr_filter.status = 1
                  AND icr_filter.category_id IN

                      #{categoryIdItem}

            )
        )


        AND (
            i.category_id = #{categoryId}
            OR EXISTS (
                SELECT 1
                FROM item_category_rel icr_filter
                WHERE icr_filter.item_id = i.id
                  AND icr_filter.deleted = 0
                  AND icr_filter.status = 1
                  AND icr_filter.category_id = #{categoryId}
            )
        )


        AND i.rarity_id = #{rarityId}


        AND i.game_period_id = #{gamePeriodId}
